-- Seed survey_template_catalog from bundled definitions + specialty stubs.
-- Regenerate: node scripts/build-survey-catalog-seed.mjs

insert into public.survey_template_catalog (
  id,
  organization_id,
  is_system,
  name,
  short_name,
  description,
  source,
  use_case,
  category,
  audience,
  estimated_minutes,
  recommend_anonymous,
  scoring_note,
  law_ref,
  body
) values
('tpl-uwes', NULL, true, 'Utrecht Work Engagement Scale (UWES-9)', 'UWES-9', 'Måler arbeidsengasjement langs tre dimensjoner: Vigor (vitalitet), Dedication (dedikasjon) og Absorption (fordypning). Validert i mer enn 30 land.', 'Schaufeli, Bakker & Salanova (2006)', 'Kartlegge medarbeidernes arbeidsengasjement og oppdage burnout-risiko.', 'wellbeing', 'internal', 5, true, 'Beregn gjennomsnitt per subscale (Vigor: Q1,Q2,Q3 · Dedication: Q4,Q5,Q6 · Absorption: Q7,Q8,Q9). Totalscore = snitt alle 9. Skala 0–6 (0=Aldri, 6=Alltid). Benchmark: >4.0 = høyt engasjement.', 'AML § 4-3', '{"version":1,"questions":[{"id":"uwes1","text":"Jeg føler meg sprudlende av energi på jobb.","type":"likert_7","required":true,"subscale":"Vigor","anchors":{"low":"Aldri","high":"Alltid"}},{"id":"uwes2","text":"Jeg er sterk og energisk på jobb.","type":"likert_7","required":true,"subscale":"Vigor","anchors":{"low":"Aldri","high":"Alltid"}},{"id":"uwes3","text":"Når jeg er på jobb, orker jeg å jobbe i lange perioder.","type":"likert_7","required":true,"subscale":"Vigor","anchors":{"low":"Aldri","high":"Alltid"}},{"id":"uwes4","text":"Jeg synes jobben min er full av mening og hensikt.","type":"likert_7","required":true,"subscale":"Dedication","anchors":{"low":"Aldri","high":"Alltid"}},{"id":"uwes5","text":"Jeg er begeistret over jobben min.","type":"likert_7","required":true,"subscale":"Dedication","anchors":{"low":"Aldri","high":"Alltid"}},{"id":"uwes6","text":"Jobben min er inspirerende for meg.","type":"likert_7","required":true,"subscale":"Dedication","anchors":{"low":"Aldri","high":"Alltid"}},{"id":"uwes7","text":"Når jeg jobber intenst, føler jeg lykke.","type":"likert_7","required":true,"subscale":"Absorption","anchors":{"low":"Aldri","high":"Alltid"}},{"id":"uwes8","text":"Jeg er fordypet i jobben min.","type":"likert_7","required":true,"subscale":"Absorption","anchors":{"low":"Aldri","high":"Alltid"}},{"id":"uwes9","text":"Jeg kommer i en slags \"flyt\" når jeg jobber.","type":"likert_7","required":true,"subscale":"Absorption","anchors":{"low":"Aldri","high":"Alltid"}}]}'::jsonb),
('tpl-google-rework', NULL, true, 'Google re:Work — Teameffektivitet', 're:Work', 'Basert på Google Project Aristotle-studien. Måler de fem faktorene som forutsier høytytende team: Psykologisk trygghet, Pålitelighet, Struktur & klarhet, Mening og Effekt.', 'Google re:Work / Project Aristotle (2016)', 'Evaluere teamdynamikk og identifisere hvilken av de fem Aristotle-faktorene som trenger styrking.', 'performance', 'internal', 7, true, 'Beregn snitt per faktor (skala 1–5). Faktorgrenser: Psykologisk trygghet: Q1–Q3 · Pålitelighet: Q4–Q5 · Struktur & klarhet: Q6–Q7 · Mening: Q8–Q9 · Effekt: Q10–Q11. Benchmark: 3.5+ per faktor = sunt team.', NULL, '{"version":1,"questions":[{"id":"rw1","text":"Hvis jeg gjør en feil i dette teamet, brukes det ikke mot meg.","type":"likert_5","required":true,"subscale":"Psykologisk trygghet","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw2","text":"Teammedlemmene er i stand til å ta opp vanskelige problemer og utfordringer.","type":"likert_5","required":true,"subscale":"Psykologisk trygghet","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw3","text":"Ingen i teamet ville handle på en måte som bevisst undergraver innsatsen min.","type":"likert_5","required":true,"subscale":"Psykologisk trygghet","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw4","text":"Teammedlemmene leverer på det de lover.","type":"likert_5","required":true,"subscale":"Pålitelighet","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw5","text":"Jeg kan stole på at teammedlemmene gjør god kvalitet i arbeidet.","type":"likert_5","required":true,"subscale":"Pålitelighet","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw6","text":"Teamet har tydelige mål, roller og planer.","type":"likert_5","required":true,"subscale":"Struktur & klarhet","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw7","text":"Prosessene for beslutningstaking i teamet er effektive.","type":"likert_5","required":true,"subscale":"Struktur & klarhet","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw8","text":"Arbeidet jeg gjør i dette teamet er meningsfullt for meg.","type":"likert_5","required":true,"subscale":"Mening","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw9","text":"Å jobbe i dette teamet gir meg mulighet til å bruke mine styrker.","type":"likert_5","required":true,"subscale":"Mening","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw10","text":"Jeg tror teamets arbeid har en positiv effekt på organisasjonen.","type":"likert_5","required":true,"subscale":"Effekt","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw11","text":"Teamets arbeid bidrar positivt til organisasjonens mål og verdier.","type":"likert_5","required":true,"subscale":"Effekt","anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"rw12","text":"Hva kan teamet gjøre annerledes for å fungere enda bedre?","type":"text","required":false}]}'::jsonb),
('tpl-enps', NULL, true, 'Employee Net Promoter Score (eNPS)', 'eNPS', 'To kjernesporsmål som måler lojalitet og anbefaling som arbeidsgiver. Rask å svare på (under 2 min). Beregn eNPS = % Promoters (9–10) minus % Detractors (0–6).', 'F. Reichheld (2003) / Adapted for employee experience', 'Rask pulsundersøkelse for å fange medarbeidernes lojalitet og anbefalingsvillighet. Egnet for månedlig/kvartalsvis kjøring.', 'engagement', 'internal', 2, true, 'eNPS = (Antall Promoters ÷ totalt) × 100 − (Antall Detractors ÷ totalt) × 100. Promoters: 9–10 · Passives: 7–8 · Detractors: 0–6. Score −100 til +100. Bransjenorm: +10 regnes som godt, +50 er fremragende.', NULL, '{"version":1,"questions":[{"id":"enps1","text":"Hvor sannsynlig er det at du vil anbefale [organisasjon] som arbeidsplass til en venn eller kollega? (0 = Svært usannsynlig, 10 = Svært sannsynlig)","type":"scale_10","required":true,"anchors":{"low":"Svært usannsynlig (0)","high":"Svært sannsynlig (10)"}},{"id":"enps2","text":"Hva er den viktigste grunnen til scoren din?","type":"text","required":false},{"id":"enps3","text":"Hva er det én ting organisasjonen kan gjøre bedre for deg som ansatt?","type":"text","required":false}]}'::jsonb),
('tpl-edmondson', NULL, true, 'Psykologisk trygghet — Edmondson 7-spørsmål', 'Edmondson PS', 'Amy Edmondsons originale 7-spørs­mål for psykologisk trygghet i team. Mye brukt i forskning og organisasjonsutvikling globalt. Grunnlaget for Google Aristotle-studien.', 'Edmondson, A.C. (1999). Administrative Science Quarterly, 44(2), 350–383.', 'Kartlegge om teammedlemmer føler seg trygge nok til å ta mellommenneskelig risiko — ytre meninger, innrømme feil, stille «dumme» spørsmål.', 'safety', 'internal', 4, true, 'Reverser Q4 og Q7 (6 − score). Beregn snitt av alle 7. Skala 1–5. Benchmark: <3.0 = lav trygghet · 3.0–3.8 = moderat · >3.8 = høy trygghet. Legg til fritekst for kvalitative funn.', 'AML § 4-3', '{"version":1,"questions":[{"id":"ed1","text":"Hvis du gjør en feil i dette teamet, holdes det ofte mot deg.","type":"likert_5","required":true,"anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"ed2","text":"Teammedlemmene er i stand til å ta opp vanskelige problemer og utfordringer.","type":"likert_5","required":true,"anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"ed3","text":"Folk i dette teamet avviser noen ganger andre fordi de er annerledes.","type":"likert_5","required":true,"anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"ed4","text":"Det er trygt å ta en risiko i dette teamet.","type":"likert_5","required":true,"anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"ed5","text":"Det er vanskelig å be andre i dette teamet om hjelp.","type":"likert_5","required":true,"anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"ed6","text":"Ingen i teamet ville bevisst handle på en måte som undergraver innsatsen min.","type":"likert_5","required":true,"anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"ed7","text":"Mine unike ferdigheter og talenter verdsettes og brukes i dette teamet.","type":"likert_5","required":true,"anchors":{"low":"Helt uenig","high":"Helt enig"}},{"id":"ed8","text":"Hva er ett konkret tiltak som ville økt den psykologiske tryggheten i teamet ditt?","type":"text","required":false}]}'::jsonb),
('tpl-hms-climate', NULL, true, 'HMS-klimamåling (norsk tilpasset)', 'HMS-klima', 'Norsk tilpasset undersøkelse av sikkerhetsklima etter Internkontrollforskriften og AML §4-3. Kartlegger om HMS-kulturen er reell og ikke bare formell.', 'Tilpasset IK-forskriften og AML §4-3 / Arbeidstilsynets veiledninger', 'Årlig HMS-klimamåling som del av systematisk HMS-arbeid (IK-f §5 nr. 5).', 'safety', 'internal', 6, true, 'Skala 1–5. Gjennomsnitt under 3.5 på enkeltspørsmål bør prioriteres i handlingsplan. Resultater dokumenteres som del av årsgjennomgang (IK-f §5 nr. 5).', 'AML § 4-3', '{"version":1,"questions":[{"id":"hc1","text":"Ledelsen tar HMS-arbeid på alvor og prioriterer det aktivt.","type":"likert_5","required":true,"subscale":"Ledelsesforpliktelse","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"hc2","text":"Jeg vet hvem jeg skal kontakte hvis jeg observerer en sikkerhetsrisiko.","type":"likert_5","required":true,"subscale":"Systemer og rutiner","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"hc3","text":"Avvik og nestenulykker meldes alltid uten frykt for konsekvenser.","type":"likert_5","required":true,"subscale":"Avvikskultur","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"hc4","text":"Jeg har fått nødvendig HMS-opplæring for arbeidet jeg gjør.","type":"likert_5","required":true,"subscale":"Opplæring","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"hc5","text":"Verneombudet er synlig og lett tilgjengelig.","type":"likert_5","required":true,"subscale":"Verneorganisasjon","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"hc6","text":"Arbeidsmengden og tidspress skaper ikke uakseptable risikoer.","type":"likert_5","required":true,"subscale":"Psykososialt","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"hc7","text":"Utstyr og arbeidsplassen er i orden og trygg å bruke.","type":"likert_5","required":true,"subscale":"Fysisk arbeidsmiljø","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"hc8","text":"Hva er det viktigste vi kan forbedre for å styrke HMS-kulturen?","type":"text","required":false}]}'::jsonb),
('tpl-qps-nordic', NULL, true, 'QPS Nordic 34+', 'QPS', 'Validert spørreskjema for psykososialt arbeidsmiljø. Dekker jobbkrav, kontroll, klima, ledelse.', 'Nordic', 'Hovedmåling (anbefalt hvert annet år).', 'wellbeing', 'internal', 7, true, 'Bruk fasit/normdata for QPS Nordic. Sammenlign delskalaer mot bransje.', 'AML § 4-3', '{"version":1,"questions":[{"id":"qps1","text":"Eksempel spørsmål 1 (full katalog i produksjon). Erstatt med importert spørsmålssett ved behov.","type":"likert_5","required":true,"subscale":"Generelt","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"qps2","text":"Eksempel spørsmål 2 (full katalog i produksjon). Erstatt med importert spørsmålssett ved behov.","type":"likert_5","required":true,"subscale":"Generelt","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"qps3","text":"Eksempel spørsmål 3 (full katalog i produksjon). Erstatt med importert spørsmålssett ved behov.","type":"likert_5","required":true,"subscale":"Generelt","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"qps4","text":"Eksempel spørsmål 4 (full katalog i produksjon). Erstatt med importert spørsmålssett ved behov.","type":"likert_5","required":true,"subscale":"Generelt","anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"qps5","text":"Eksempel spørsmål 5 (full katalog i produksjon). Erstatt med importert spørsmålssett ved behov.","type":"likert_5","required":true,"subscale":"Generelt","anchors":{"low":"Svært uenig","high":"Svært enig"}}]}'::jsonb),
('tpl-ark', NULL, true, 'ARK Arbeidsmiljø', 'ARK', 'Bredt validert instrument for norsk arbeidsliv. Også eNPS-linje og fysisk/organisatorisk miljø.', 'NTNU', 'Hovedmåling for større virksomheter.', 'safety', 'internal', 12, true, 'Følg ARK-veiledning for terskler og rapportering.', 'AML § 4-3', '{"version":1,"questions":[{"id":"ark1","text":"ARK — eksempelspørsmål 1 (erstatt med full ARK-pakke ved lisens).","type":"likert_5","required":true,"anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"ark2","text":"ARK — eksempelspørsmål 2 (erstatt med full ARK-pakke ved lisens).","type":"likert_5","required":true,"anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"ark3","text":"ARK — eksempelspørsmål 3 (erstatt med full ARK-pakke ved lisens).","type":"likert_5","required":true,"anchors":{"low":"Svært uenig","high":"Svært enig"}},{"id":"ark4","text":"ARK — eksempelspørsmål 4 (erstatt med full ARK-pakke ved lisens).","type":"likert_5","required":true,"anchors":{"low":"Svært uenig","high":"Svært enig"}}]}'::jsonb),
('tpl-pulse', NULL, true, 'Pulsmåling 4 spm.', 'Puls', 'Kort puls mellom hovedmålinger — fanger endringer raskt.', 'Klarert', 'Kvartalsvis.', 'engagement', 'internal', 1, true, 'Sammenlign mot siste hovedmåling.', NULL, '{"version":1,"questions":[{"id":"p1","text":"Hvordan vurderer du arbeidsmiljøet ditt akkurat nå?","type":"likert_5","required":true},{"id":"p2","text":"Føler du at du har tilstrekkelig støtte fra nærmeste leder?","type":"likert_5","required":true},{"id":"p3","text":"Hvor sannsynlig er det at du anbefaler oss som arbeidsplass? (0–10)","type":"scale_10","required":true},{"id":"p4","text":"Kort kommentar (valgfritt).","type":"text","required":false}]}'::jsonb),
('tpl-mobbing', NULL, true, 'Mobbing & trakassering (fordypning)', 'Mobbing', 'Brukes når hovedmålingen viser røde flagg. Krever sterk anonymitet.', 'Klarert', 'Oppfølging etter varsler.', 'safety', 'internal', 6, true, 'Kun aggregert rapportering. Svar under terskel skjules.', 'AML § 4-3 (3)', '{"version":1,"questions":[{"id":"mb1","text":"Har du i løpet av siste 12 mnd. vært utsatt for uønsket atferd som har vart over tid?","type":"yes_no","required":true},{"id":"mb2","text":"Beskriv kort (valgfritt) — svar behandles konfidensielt.","type":"text","required":false},{"id":"mb3","text":"Hvordan opplever du muligheten til å si ifra?","type":"likert_5","required":true}]}'::jsonb),
('tpl-exit', NULL, true, 'Sluttundersøkelse', 'Exit', 'Til medarbeidere som slutter — forstå frafall.', 'Klarert', 'Ved oppsigelse.', 'engagement', 'internal', 5, true, 'Kobles til arbeidsflyt «utmelding».', NULL, '{"version":1,"questions":[{"id":"ex1","text":"Hovedårsak til at du slutter (velg én):","type":"single_select","required":true},{"id":"ex2","text":"Hva kunne vi gjort annerledes?","type":"text","required":false},{"id":"ex3","text":"Vil du anbefale oss? (0–10)","type":"scale_10","required":true}]}'::jsonb),
('tpl-onboarding', NULL, true, 'Onboarding 30 dager', 'Onboarding', '30 dager etter ansettelse — mottakelse og opplæring.', 'Klarert', 'Auto-utsending', 'wellbeing', 'internal', 4, false, 'Kobles til startdato.', NULL, '{"version":1,"questions":[{"id":"on1","text":"Fikk du den opplæringen du trengte for jobben?","type":"likert_5","required":true},{"id":"on2","text":"Føler du deg inkludert i teamet?","type":"likert_5","required":true},{"id":"on3","text":"Hva var best / verst så langt?","type":"text","required":false}]}'::jsonb),
('ext-hms-egenerklaring', NULL, true, 'HMS-egenerklæring (leverandør)', 'HMS-eg', 'Standardisert egenerklæring for leverandører — internkontroll, opplæring, forsikring.', 'Klarert', 'Årlig fra underleverandører.', 'vendor', 'external', 10, false, 'Filvedlegg kan legges til i arbeidsflyt.', 'IK-forskriften § 5', '{"version":1,"questions":[{"id":"v1","text":"Har virksomheten skriftlig HMS-system etter internkontrollforskriften?","type":"yes_no","required":true},{"id":"v2","text":"Bekreft at relevant personell er opplært i HMS for de tjenestene dere leverer.","type":"yes_no","required":true},{"id":"v3","text":"Har dere gyldig ansvarsforsikring?","type":"single_select","required":true},{"id":"v4","text":"Kort beskrivelse av sikker jobb-utførelse hos kunde (valgfritt).","type":"text","required":false}]}'::jsonb),
('ext-underentreprenor', NULL, true, 'Underentreprenør — byggeplass', 'UE bygg', 'SHA-plan, ID-kort, arbeidsforhold før oppstart på byggeplass.', 'Klarert', 'Bygg/anlegg.', 'vendor', 'external', 15, false, 'Krever signatur efter behov.', 'Byggherreforskriften', '{"version":1,"questions":[{"id":"u1","text":"Er SHA-plan for arbeidet tilgjengelig og gjennomgått?","type":"yes_no","required":true},{"id":"u2","text":"Er ID-kort/seriøsitet verifisert?","type":"yes_no","required":true},{"id":"u3","text":"Risikonivå for arbeidet (1–10)","type":"scale_10","required":true},{"id":"u4","text":"Merknader / forbehold","type":"text","required":false}]}'::jsonb),
('ext-apenhetsloven', NULL, true, 'Etiske retningslinjer / menneskerettigheter', 'Åpenhet', 'Bekreftelse i tråd med åpenhetsloven — rettigheter og anstendige arbeidsforhold.', 'Klarert', 'Leverandørscreening.', 'compliance', 'external', 6, false, 'Dokumenter i revidering av leverandørregister.', 'Åpenhetsloven § 4', '{"version":1,"questions":[{"id":"a1","text":"Er menneskerettigheter respektert i egen virksomhet og viktigste underleverandører?","type":"yes_no","required":true},{"id":"a2","text":"Har dere skriftlige retningslinjer for menneskerettigheter og rettferdig lønn?","type":"yes_no","required":true},{"id":"a3","text":"Beskriv kort hvordan dere følger opp underleverandører (valgfritt).","type":"text","required":false}]}'::jsonb),
('tpl-klarert-tilpasset', NULL, true, 'Tilpasset mal — start her', 'Ny mal', 'Tom eller nesten tom mal for å definere egne spørsmål og kriterier (kopier og tilpass).', 'Klarert', 'Egendefinerte undersøkelser.', 'custom', 'both', 5, true, 'Legg til spørsmål i byggeren etter opprettelse.', NULL, '{"version":1,"questions":[]}'::jsonb)
on conflict (id) do update set
  name = excluded.name,
  short_name = excluded.short_name,
  description = excluded.description,
  source = excluded.source,
  use_case = excluded.use_case,
  category = excluded.category,
  audience = excluded.audience,
  estimated_minutes = excluded.estimated_minutes,
  recommend_anonymous = excluded.recommend_anonymous,
  scoring_note = excluded.scoring_note,
  law_ref = excluded.law_ref,
  body = excluded.body,
  updated_at = now();
